// Normaliza o payload canônico Destrava v2
const body = $input.first().json;

// Suporte a payload aninhado (v2) e legado (raiz)
const lead        = body.lead || {};
const simulation  = body.simulation || {};
const context     = body.context || {};
const routing     = body.routing || {};

const id              = lead.id              || body.id              || null;
const nome            = lead.nome            || body.nome            || '';
const telefone        = lead.telefone        || body.telefone        || '';
const email           = lead.email           || body.email           || null;
const empresa         = lead.empresa         || body.empresa         || null;
const tipo_pessoa     = lead.tipo_pessoa     || body.tipo_pessoa     || 'pf';
const origem          = lead.origem          || body.source          || body.origem || 'site';
const produto         = lead.produto_interesse || body.produto       || null;

const valor_solicitado = simulation.valor_solicitado || body.valorSolicitado || null;
const prazo_meses      = simulation.prazo            || body.prazo           || null;
const parcela_estimada = simulation.parcela_estimada || null;
const taxa_estimada    = simulation.taxa_estimada    || null;

const utm_source   = context.utm_source   || null;
const utm_medium   = context.utm_medium   || null;
const utm_campaign = context.utm_campaign || null;
const pagina       = context.pagina       || '/simular';

// Classificação automática de temperatura
let temperatura = 'frio';
if (valor_solicitado >= 100000)  temperatura = 'quente';
if (valor_solicitado >= 500000)  temperatura = 'urgente';
if (origem === 'simulador_publico') temperatura = temperatura === 'frio' ? 'morno' : temperatura;

// Score simples baseado em dados disponíveis
let score = 10;
if (nome)             score += 15;
if (telefone)         score += 20;
if (email)            score += 10;
if (empresa)          score += 10;
if (valor_solicitado) score += 15;
if (prazo_meses)      score += 10;
if (utm_source)       score += 5;
if (origem === 'simulador_publico') score += 5;

// Linha recomendada
let linha_recomendada = null;
if (tipo_pessoa === 'pj' || tipo_pessoa === 'empresa') {
  if (valor_solicitado <= 150000) linha_recomendada = 'PRONAMPE';
  else if (valor_solicitado <= 360000) linha_recomendada = 'ProCred 360';
  else linha_recomendada = 'PEAC FGI';
} else {
  linha_recomendada = 'Crédito Pessoal';
}

return [{
  json: {
    id, nome, telefone, email, empresa, tipo_pessoa, origem, produto,
    valor_solicitado, prazo_meses, parcela_estimada, taxa_estimada,
    utm_source, utm_medium, utm_campaign, pagina,
    temperatura, score_ia: score, linha_recomendada,
    etapa_funil: 'novo',
    status: 'novo',
    updated_at: new Date().toISOString(),
  }
}];
